import * as Blockly from 'blockly/core';

const WEB_COLOR = 120;

export const wifi_init = {
    init: function () {
        this.setColour(WEB_COLOR);
        this.appendDummyInput("")
            .appendField(Blockly.Msg.MIXLY_WIFI_INIT)
            .appendField(new Blockly.FieldImage(require("../media/web.png"), 52, 40));
        this.appendValueInput("SSID", String)
            .setCheck([String, Number])
            .setAlign(Blockly.ALIGN_RIGHT)
            .appendField("SSID")
            .appendField(Blockly.Msg.MIXLY_WIFI_NAME);
        this.appendValueInput("PASSWD", String)
            .setCheck([String, Number])
            .setAlign(Blockly.ALIGN_RIGHT)
            .appendField("PASSWD")
            .appendField(Blockly.Msg.MIXLY_WIFI_PASSWORD);
        this.setPreviousStatement(true, null);
        this.setNextStatement(true, null);
        this.setTooltip('');
    }
};


