export const wifi_data_read = {
    init: function () {
        this.setColour(WEB_COLOR);
        this.appendDummyInput("")
            .appendField(new Blockly.FieldImage(require("../media/web.png"), 52, 40))
            .appendField(Blockly.Msg.SEND_SENOR_DATA)
            .appendField(new Blockly.FieldDropdown([
                ['Water', 'WATER'],
                ['Temperature', 'TEMP'],
                ['Humidity', 'HUM'],
                ['Light', 'LIGHT'],
                ['Ultrasonic', 'ULTRA'],
                ['Smoke', 'SMOKE'],
                ['Alcohol', 'ALCOHOL'],
                ['Soil', 'SOIL'],
                ['Pot', 'POT'],
            ]), 'send_sensor_name');
        this.appendValueInput('value')
            .setCheck(Number)
            .appendField(Blockly.Msg.SENSOR_Value);
        this.setInputsInline(true); // 横向排列（传感器类型+数值输入框在同一行）
        this.setOutput(true, String);
    }
};


